const BASE = "http://localhost:5000/api";

function headers(token) {
  return {
    "Content-Type": "application/json",
    ...(token ? { Authorization: `Bearer ${token}` } : {}),
  };
}

async function request(method, path, body, token) {
  const res = await fetch(`${BASE}${path}`, {
    method,
    headers: headers(token),
    body: body ? JSON.stringify(body) : undefined,
  });
  const data = await res.json();
  if (!res.ok) throw new Error(data.error || "Request failed");
  return data;
}

// Auth
export const apiLogin    = (email, password) =>
  request("POST", "/auth/login",    { email, password });
export const apiRegister = (name, email, password, role) =>
  request("POST", "/auth/register", { name, email, password, role });

// Energy
export const apiStats    = (token) => request("GET",  "/energy/stats",    null, token);
export const apiReadings = (token, hours = 24) =>
  request("GET", `/energy/readings?hours=${hours}`, null, token);
export const apiZones    = (token) => request("GET",  "/energy/zones",    null, token);
export const apiSimulate = (token) => request("POST", "/energy/simulate", {}, token);
export const apiPredict  = (token) => request("GET",  "/energy/predict",  null, token);

// Reports
export const apiDailyReport  = (token, days = 7) =>
  request("GET", `/reports/daily?days=${days}`, null, token);
export const apiHourlyReport = (token) =>
  request("GET", "/reports/hourly", null, token);

// Alerts
export const apiAlerts      = (token) => request("GET",  "/alerts/",                  null,  token);
export const apiResolveAlert = (token, id) =>
  request("PATCH", `/alerts/${id}/resolve`, {}, token);
export const apiResolveAll  = (token) => request("PATCH", "/alerts/resolve-all",       {}, token);

// Settings
export const apiGetSettings    = (token) => request("GET",  "/settings/",  null, token);
export const apiUpdateSettings = (token, data) =>
  request("POST", "/settings/", data, token);
